extern "C" void mixbenchGPU(double* c, long size) {
  const size_t size_elements = static_cast<size_t>(size);
  const size_t size_bytes = size_elements * sizeof(double);

  void* d_buffer = nullptr;
  void* d_partials = nullptr;

  const size_t max_len = size_bytes / sizeof(int);
  const int max_blocks = choose_blocks(max_len);

  CUDA_SAFE_CALL(cudaMalloc(&d_buffer, size_bytes));
  CUDA_SAFE_CALL(cudaMalloc(&d_partials, static_cast<size_t>(max_blocks) *
                                             sizeof(double)));
  CUDA_SAFE_CALL(cudaMemset(d_buffer, 0, size_bytes));

  std::cout << "--------------------------------------------"
               "-------------- CSV data "
               "--------------------------------------------"
               "--------------"
            << std::endl;
  std::cout << "Experiment ID, Single Precision ops,,,,              Double "
               "precision ops,,,,              Integer operations,,, "
            << std::endl;
  std::cout << "Compute iters, Flops/byte, ex.time,  GFLOPS, GB/sec, "
               "Flops/byte, ex.time,  GFLOPS, GB/sec, Iops/byte, ex.time,   "
               "GIOPS, GB/sec"
            << std::endl;

  runbench_warmup(d_buffer, d_partials, size_bytes);

  runbench_range<0, 1, 2, 3, 4, 6, 8, 12, 16, 20, 24, 28, 32, 40, 6 * 8, 7 * 8,
                 8 * 8, 10 * 8, 13 * 8, 15 * 8, 16 * 8, 20 * 8, 24 * 8, 32 * 8,
                 40 * 8, 64 * 8>(d_buffer, d_partials, size_bytes);

  std::cout << "---------------------------------------------------------------"
               "---------------------------------------------------------------"
            << std::endl;

  if (c != nullptr) {
    std::memset(c, 0, size_bytes);
  }

  CUDA_SAFE_CALL(cudaFree(d_partials));
  CUDA_SAFE_CALL(cudaFree(d_buffer));
}
